import "@fhenixprotocol/contracts/FHE.sol";
import {Permissioned, Permission} from "@fhenixprotocol/contracts/access/Permissioned.sol";

contract Counter is Permissioned {
  euint32 private counter;
  address public owner;

  constructor() {
    owner = msg.sender;
  }

  function add(inEuint32 calldata encryptedValue) public {
    euint32 value = FHE.asEuint32(encryptedValue);
    counter = counter + value;
  }

  function getCounter() public view returns (uint256) {
    return FHE.decrypt(counter);
  }

  function getCounterPermit(
    Permission memory permission
  ) public view onlySender(permission) returns (uint256) {
    return FHE.decrypt(counter);
  }

  function getCounterPermitSealed(
    Permission memory permission
  ) public view onlySender(permission) returns (string memory) {
    return FHE.sealoutput(counter, permission.publicKey);
  }
}

import { Counter } from "../typechain-types";
import { task } from "hardhat/config";
import type { TaskArguments } from "hardhat/types";

task("task:getCount").setAction(async function (
  _taskArguments: TaskArguments,
  hre,
) {
  const { fhenixjs, ethers, deployments } = hre;
  const [signer] = await ethers.getSigners();

  const Counter = await deployments.get("Counter");

  console.log(`Running getCount, targeting contract at: ${Counter.address}`);

  const contract = (await ethers.getContractAt(
    "Counter",
    Counter.address,
  )) as unknown as unknown as Counter;

  let permit = await fhenixjs.generatePermit(
    Counter.address,
    undefined, // use the internal provider
    signer,
  );
  const permission = fhenixjs.extractPermitPermission(permit);

  const result = await contract.getCounterPermit(permission);
  console.log(`got count: ${result.toString()}`);

  const sealedResult = await contract.getCounterPermitSealed(permit);
  let unsealed = fhenixjs.unseal(Counter.address, sealedResult, signer.address);

  console.log(`got unsealed result: ${unsealed.toString()}`);
});

import type { HookContext, NetworkHooks } from "hardhat/types/hooks";
import type { ChainType, NetworkConnection } from "hardhat/types/network";

import { initializeViem } from "../initialization.js";

export default async (): Promise<Partial<NetworkHooks>> => {
  const handlers: Partial<NetworkHooks> = {
    async newConnection<ChainTypeT extends ChainType | string>(
      context: HookContext,
      next: (
        nextContext: HookContext,
      ) => Promise<NetworkConnection<ChainTypeT>>,
    ) {
      const connection: NetworkConnection<ChainTypeT> = await next(context);

      connection.viem = initializeViem(
        connection.chainType,
        connection.provider,
        context.artifacts,
        context.config.chainDescriptors,
        connection.networkName,
      );

      return connection;
    },
  };

  return handlers;
};

